/**
 * Measures the generic {@code InnerMergeJoinIterator} over ordered LMDB scans with the advisory statement-level seek
 * enabled versus disabled, on an object join whose smaller side covers alternating key blocks: at {@code blockSize =
 * 1} the sides interleave row by row (gaps below the seek threshold — the guard case), at {@code blockSize = 1000} the
 * dense side crosses thousand-row gaps that one cursor seek can skip. Both sides stay within the optimizer's 10x
 * size-difference gate (2:1), and the standard (order-aware) evaluation strategy is used so the optimizer actually
 * selects the merge join. Setup verifies via explain that the merge join runs, so a silently different plan fails the
 * run instead of measuring the wrong thing.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class MergeJoinLeapfrogBenchmark {

	private static final String EX = "http://example.com/";
	private static final String SEEK_FLAG = "rdf4j.lmdb.statementSeek.enabled";

	private static final int DENSE_ROWS = 100_000;

	@Param({ "true", "false" })
	public String seekEnabled;

	/** The smaller side covers alternating blocks of this many keys, so gaps are the same size as the blocks. */
	@Param({ "1", "1000" })
	public int blockSize;

	private File dataDir;
	private SailRepository repository;
	private String query;
	private long expectedRows;

	@Setup(Level.Trial)
	public void setUp() {
		System.setProperty(SEEK_FLAG, seekEnabled);
		dataDir = Files.newTemporaryFolder();
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		store.setEvaluationStrategyFactory(new DefaultEvaluationStrategyFactory());
		repository = new SailRepository(store);
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI dense = vf.createIRI(EX, "p1");
			IRI sparse = vf.createIRI(EX, "p2");
			conn.begin();
			expectedRows = 0;
			for (int i = 0; i < DENSE_ROWS; i++) {
				// object join: with the predicates bound, both sides scan a contiguous posc prefix range
				// ordered on ?x — the shape ordered scans (and thus the merge join) are cheap for
				IRI joinObject = vf.createIRI(EX, "x" + i);
				conn.add(vf.createIRI(EX, "a" + i), dense, joinObject);
				if ((i / blockSize) % 2 == 0) {
					conn.add(vf.createIRI(EX, "b" + i), sparse, joinObject);
					expectedRows++;
				}
			}
			conn.commit();
		}
		query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?a ?b ?x WHERE { ?b ex:p2 ?x . ?a ex:p1 ?x }";
		verifyMergeJoinEngagement();
	}

	private void verifyMergeJoinEngagement() {
		String plan;
		try (SailRepositoryConnection conn = repository.getConnection()) {
			plan = conn.prepareTupleQuery(query).explain(Explanation.Level.Executed).toString();
		}
		if (!plan.contains("InnerMergeJoinIterator")) {
			throw new IllegalStateException("expected an InnerMergeJoinIterator plan but was:\n" + plan);
		}
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		repository.shutDown();
		FileUtil.deleteDir(dataDir);
		System.clearProperty(SEEK_FLAG);
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			long rows = 0;
			try (TupleQueryResult result = conn.prepareTupleQuery(query).evaluate()) {
				while (result.hasNext()) {
					result.next();
					rows++;
				}
			}
			if (rows != expectedRows) {
				throw new IllegalStateException("expected " + expectedRows + " rows but got " + rows);
			}
			return rows;
		}
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("MergeJoinLeapfrogBenchmark")
				.build();
		new Runner(opt).run();
	}
}
